CustomField.formula:
( /* 選択リスト（None/--None--も未入力扱い） */ IF( AND( NOT(ISBLANK(TEXT(SalesDepartment__c))), TEXT(SalesDepartment__c) <> "None", TEXT(SalesDepartment__c) <> "--None--"), 1, 0) + IF( AND( NOT(ISBLANK(TEXT(PurchasingDepartment__c))), TEXT(PurchasingDepartment__c) <> "None", TEXT(PurchasingDepartment__c) <> "--None--"), 1, 0) + IF( AND( NOT(ISBLANK(TEXT(ConstructionDivision__c))), TEXT(ConstructionDivision__c) <> "None", TEXT(ConstructionDivision__c) <> "--None--"), 1, 0) + IF( AND( NOT(ISBLANK(TEXT(SDGsDepartment__c))), TEXT(SDGsDepartment__c) <> "None", TEXT(SDGsDepartment__c) <> "--None--"), 1, 0) +
/* テキスト（空白のみを未入力扱い） */ IF( LEN(TRIM(wasteMaterial__c)) > 0, 1, 0 ) + IF( LEN(TRIM(wasteMaterial1__c)) > 0, 1, 0 ) + IF( LEN(TRIM(wasteMaterial2__c)) > 0, 1, 0 ) + IF( LEN(TRIM(wasteMaterial3__c)) > 0, 1, 0 ) + IF( LEN(TRIM(wasteMaterialCarrier__c)) > 0, 1, 0 ) +
/* 通貨（0 を未入力扱いにするなら <> 0 を追加） */ IF( AND( NOT(ISBLANK(wasteMaterialYen__c)), wasteMaterialYen__c <> 0), 1, 0 ) )
